member.example:
Bind the Graphic material property using a serialized binder field — the target Graphic is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GraphicMaterialBinder _material;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Material _material;
    }


Bind the Graphic material property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private RawImage _image;
        
        private GraphicMaterialBinder Material =>
            new(_image);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Material _material;
    }

Switch the Graphic material between two values using a serialized binder field — the target Graphic is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GraphicMaterialSwitcherBinder _isAlternate;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isAlternate;
    }


Switch the Graphic material between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private RawImage _image;
        [SerializeField] private Material _alternateMaterial;
        [SerializeField] private Material _defaultMaterial;
        
        private GraphicMaterialSwitcherBinder IsAlternate => new(
            _image, _alternateMaterial, _defaultMaterial);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isAlternate;
    }
